__forceinline__ __device__ int32_t warp_reduce_max(int32_t val) {
  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    int32_t other = __shfl_xor_sync(0xffffffffu, val, offset);
    val = max(val, other);
  }
  return val;
}

__forceinline__ __device__ int32_t warp_reduce_sum(int32_t val) {
  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    val += __shfl_down_sync(0xffffffffu, val, offset);
  }
  return val;
}

__global__ void softmax_int32_kernel(
  const int32_t* __restrict__ input,  // Q15.16
  const int32_t* __restrict__ lut,    // Q15.16
  uint32_t* __restrict__ out,         // Q0.32
  uint32_t C)
{
  extern __shared__ int32_t sdata[];

  uint32_t thread_idx = threadIdx.x;
  uint32_t lane_idx = thread_idx & 31;
  uint32_t warp_idx = thread_idx >> 5;
  uint32_t n_warps = (blockDim.x + 31) / 32;
  uint32_t row_start_idx = blockIdx.x * C + thread_idx;
  uint32_t row_end_idx = blockIdx.x * C + C;

  int32_t local_max = INT32_MIN;
  for (uint32_t idx = row_start_idx; idx < row_end_idx; idx += blockDim.x) {
    if (input[idx] > local_max) local_max = input[idx];
  }
  int32_t warp_max = warp_reduce_max(local_max);
  if (lane_idx == 0) sdata[warp_idx] = warp_max;
  __syncthreads();
  if (warp_idx == 0) {
    int32_t v = INT32_MIN;
    for (uint32_t i = lane_idx; i < n_warps; i += 32) {
      v = max(v, sdata[i]);
    }
    int32_t m = warp_reduce_max(v);
    if (lane_idx == 0) sdata[0] = m;
  }
  __syncthreads();
  int32_t row_max = sdata[0] + (1 << 6);  // plus (1 << 6) for rounding
  __syncthreads();

  int32_t local_sum = 0;
  for (uint32_t idx = row_start_idx; idx < row_end_idx; idx += blockDim.x) {
    int32_t id = (row_max - input[idx]) >> 7;
    if (id > EXP_LUT_SIZE - 1) id = EXP_LUT_SIZE - 1;
    local_sum += lut[id];
  }
  int32_t warp_sum = warp_reduce_sum(local_sum);
  if (lane_idx == 0) sdata[warp_idx] = warp_sum;
  __syncthreads();
  if (warp_idx == 0) {
    int32_t v = 0;
    for (uint32_t i = lane_idx; i < n_warps; i += 32) {
      v += sdata[i];
    }
    int32_t m = warp_reduce_sum(v);
    if (lane_idx == 0) sdata[0] = m;
  }
  __syncthreads();
  int32_t row_sum = sdata[0];

  // If row_sum == 0, fallback to uniform distribution
  uint64_t inv;
  if (row_sum > 0) {
    inv = ((uint64_t(1) << 32) + (row_sum >> 1)) / (uint64_t)row_sum;
  } else {
    inv = (uint64_t(1) << 32) / (uint64_t)C;
  }

  for (uint32_t idx = row_start_idx; idx < row_end_idx; idx += blockDim.x) {
    int32_t id = (row_max - input[idx]) >> 7;
    if (id > EXP_LUT_SIZE - 1) id = EXP_LUT_SIZE - 1;
    uint64_t prod = (uint64_t)lut[id] * inv;
    out[idx] = (prod > UINT32_MAX) ? UINT32_MAX : (uint32_t)prod;
  }
}

std::vector<int32_t> build_lut() {
  std::vector<int32_t> lut(EXP_LUT_SIZE);
  for (uint32_t k = 0; k < EXP_LUT_SIZE; ++k) {
    double x = -((double)k) / 512.0;
    double v = std::exp(x);
    int32_t val = (int32_t)std::llround(v * 65536.0);  // scale = 2^16
    lut[k] = val;
  }
  return lut;
}

at::Tensor softmax_int32(const at::Tensor &input) {
  at::Device device = input.device();
  TORCH_CHECK(device.is_cuda());

  int64_t N = input.size(0);
  int64_t C = input.size(1);
  TORCH_CHECK(N > 0 && C > 1);

  auto options = at::TensorOptions().dtype(at::kUInt32).device(device);
  at::Tensor out = at::empty({N, C}, options);

  init_exp_lookup_table(device);

  int64_t threads = std::min(int64_t(256), ((C + int64_t(31)) / 32) * 32);
  int64_t blocks = N;
  size_t shared_bytes = sizeof(int32_t) * ((threads + 31) / 32);

  cudaStream_t stream = at::cuda::getCurrentCUDAStream(device.index());
  softmax_int32_kernel<<<blocks, threads, shared_bytes, stream>>>(
    input.data_ptr<int32_t>(),
    exp_lookup_table_gpu.data_ptr<int32_t>(),
    out.data_ptr<uint32_t>(),
    C);
  return out;
}

